/**
 * Token management utilities
 *
 * Provides token estimation and history truncation for context window management.
 */

import { ChatMessage } from './AgentRuntime';

/**
 * Estimate tokens in text (4 chars ≈ 1 token)
 * For precision, use tiktoken (but it's heavy)
 */
export function estimateTokens(text: string): number {
  if (!text) return 0;
  return Math.ceil(text.length / 4);
}

/**
 * Estimate total tokens in messages array
 */
export function estimateMessagesTokens(messages: ChatMessage[]): number {
  return messages.reduce((total, msg) => {
    const content = typeof msg.content === 'string' ? msg.content : '';
    const toolCalls = msg.tool_calls ? JSON.stringify(msg.tool_calls) : '';
    const toolCallId = msg.tool_call_id || '';
    return total + estimateTokens(content + toolCalls + toolCallId) + 4; // +4 for role overhead
  }, 0);
}

/**
 * Options for history truncation
 */
export interface TruncateOptions {
  /** Always preserve system messages */
  preserveSystem?: boolean;
  /** Always preserve last N messages */
  preserveLastN?: number;
}

/**
 * Truncate history while preserving important messages
 *
 * Uses a sliding window approach that keeps recent messages and
 * fills remaining budget with older messages from most recent to oldest.
 */
export function truncateHistory(
  messages: ChatMessage[],
  maxTokens: number,
  options: TruncateOptions = {}
): ChatMessage[] {
  const { preserveLastN = 4 } = options;

  if (messages.length <= preserveLastN) {
    return messages;
  }

  // Always preserve the last N messages
  const lastMessages = messages.slice(-preserveLastN);
  const olderMessages = messages.slice(0, -preserveLastN);

  let tokens = estimateMessagesTokens(lastMessages);
  const kept: ChatMessage[] = [...lastMessages];

  // Add older messages from most recent to oldest until budget is exhausted
  for (let i = olderMessages.length - 1; i >= 0; i--) {
    const msgTokens = estimateMessagesTokens([olderMessages[i]]);
    if (tokens + msgTokens > maxTokens) break;
    kept.unshift(olderMessages[i]);
    tokens += msgTokens;
  }

  console.log(`[AgentSDK] Context window: ${tokens}/${maxTokens} tokens, ${kept.length}/${messages.length} messages`);
  return kept;
}

/**
 * Summarize old history messages (requires LLM call)
 *
 * This is a placeholder that returns a simple summary.
 * For better results, integrate with the actual LLM.
 */
export async function summarizeHistory(
  messages: ChatMessage[],
  llmCall: (prompt: string) => Promise<string>
): Promise<string> {
  if (messages.length === 0) return '';

  const prompt = `Summarize this conversation in 2-3 sentences, keeping key information:
${messages.map((m) => `${m.role}: ${m.content}`).join('\n')}`;

  return llmCall(prompt);
}

/**
 * Create a summary message to prepend to truncated history
 */
export function createSummaryMessage(summary: string): ChatMessage {
  return {
    role: 'user',
    content: `[Previous conversation summary: ${summary}]`,
  };
}
