/**
 * createAgentRoute - Cria um route handler Next.js pronto para usar
 *
 * Abstrai toda a lógica de SSE, histórico, confirmações e tool calling.
 */

import { NextRequest } from 'next/server';
import { AgentRuntime, RuntimeTool, RuntimeCallbacks, ContextWindowConfig, ResponseSchemaConfig, PromptEnhancerConfig, type ProviderConfig } from '../core';
import { HistoryStore, memoryStore } from '../core/history';

type MaybePromise<T> = T | Promise<T>;

export interface AgentRouteContext {
  req: NextRequest;
  body: Record<string, any>;
}

type RouteResolver<T> = (context: AgentRouteContext) => MaybePromise<T>;
type ResolvableRouteValue<T> = T | RouteResolver<T>;

export interface AgentRouteConfig<T = any> {
  /** Provider config */
  provider: ResolvableRouteValue<ProviderConfig>;
  /** System prompt */
  systemPrompt: ResolvableRouteValue<string>;
  /** Tools disponíveis */
  tools: ResolvableRouteValue<RuntimeTool[]>;
  /** History store (default: memory) */
  historyStore?: ResolvableRouteValue<HistoryStore>;
  /** Tamanho do histórico (default: 20) */
  historySize?: number;
  /** Temperatura (default: 0.5) */
  temperature?: number;
  /** Máximo de iterações (default: 10) */
  maxIterations?: number;
  /** Timeout por tool execution em ms (default: 30000) */
  toolExecutionTimeout?: number;
  /** Máximo de retries por iteração quando tool falha com erro retryable (default: 2) */
  maxRetriesPerIteration?: number;
  /** Context window management (token-based truncation) */
  contextWindow?: ContextWindowConfig;
  /** Reasoning configuration */
  reasoning?: {
    enabled: boolean;
    format: 'react' | 'cot' | 'auto';
    includeInHistory?: boolean;
  };
  /** Structured output configuration with Zod validation */
  responseSchema?: ResponseSchemaConfig<T>;
  /** Prompt enhancement configuration (auto-injects date/time context by default) */
  promptEnhancer?: PromptEnhancerConfig;
}

/**
 * Cria um POST handler para Next.js App Router
 * 
 * @example
 * ```ts
 * // app/api/chat/route.ts
 * import { createAgentRoute, defineTool } from '@koiketec/agent-sdk';
 * import { openaiProvider } from '@koiketec/agent-sdk/providers';
 * import { z } from 'zod';
 * 
 * const tools = [
 *   defineTool({
 *     name: 'create_product',
 *     description: 'Cria um produto',
 *     parameters: z.object({
 *       name: z.string().describe('Nome do produto'),
 *       price: z.number().describe('Preço'),
 *     }),
 *     execute: async (args) => {
 *       return await db.product.create({ data: args });
 *     },
 *   }),
 * ];
 * 
 * export const POST = createAgentRoute({
 *   provider: openaiProvider({
 *     baseUrl: 'https://api.z.ai/api/paas/v4',
 *     apiKey: process.env.AI_API_KEY!,
 *     model: 'glm-4.7-flash',
 *   }),
 *   systemPrompt: 'Você é um assistente...',
 *   tools,
 * });
 * ```
 */
export function createAgentRoute(config: AgentRouteConfig) {
  const defaultHistoryStore = memoryStore();
  const confirmPending = new Map<
    string,
    { resolve: (confirmed: boolean) => void }
  >();

  return async function POST(req: NextRequest) {
    const encoder = new TextEncoder();

    try {
      const body = await req.json();
      const routeContext: AgentRouteContext = { req, body };
      const { message, sessionId, retryLast, confirmId, confirmed } = body;

      console.log('[AgentSDK] Request received:', {
        sessionId,
        message: message?.substring(0, 50),
        retryLast,
        confirmId,
        confirmed
      });

      if (!sessionId) {
        console.log('[AgentSDK] Error: sessionId missing');
        return new Response(
          JSON.stringify({ error: 'sessionId é obrigatório' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } }
        );
      }

      // Resolver confirmação pendente
      if (confirmId !== undefined) {
        console.log('[AgentSDK] Resolving confirmation:', confirmId, confirmed);
        const key = `${sessionId}:${confirmId}`;
        const pending = confirmPending.get(key);
        if (pending) {
          confirmPending.delete(key);
          pending.resolve(confirmed === true);
        }
        return new Response(JSON.stringify({ ok: true }), {
          status: 200,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      if (!retryLast && !message) {
        console.log('[AgentSDK] Error: message missing');
        return new Response(
          JSON.stringify({ error: 'message é obrigatório' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } }
        );
      }

      const historyStore = await resolveAgentRouteValue(
        config.historyStore,
        routeContext,
        defaultHistoryStore
      );

      let history = await historyStore.get(sessionId);
      console.log('[AgentSDK] History loaded:', history.length, 'messages');

      if (retryLast) {
        // Remove última mensagem do assistente
        while (history.length > 0 && history[history.length - 1].role !== 'user') {
          history = history.slice(0, -1);
        }
        if (!history.some((m) => m.role === 'user')) {
          return new Response(
            JSON.stringify({ error: 'Nenhuma mensagem para reenviar' }),
            { status: 400, headers: { 'Content-Type': 'application/json' } }
          );
        }
      } else {
        history.push({ role: 'user', content: message });
      }

      const provider = await resolveAgentRouteValue(config.provider, routeContext);
      const systemPrompt = await resolveAgentRouteValue(config.systemPrompt, routeContext);
      const tools = await resolveAgentRouteValue(config.tools, routeContext);

      console.log('[AgentSDK] Provider config:', {
        baseUrl: provider.baseUrl,
        model: provider.model,
        hasApiKey: !!provider.apiKey
      });

      // Cria runtime
      const runtime = new AgentRuntime({
        provider,
        systemPrompt,
        tools,
        historySize: config.historySize,
        temperature: config.temperature,
        maxIterations: config.maxIterations,
        toolExecutionTimeout: config.toolExecutionTimeout,
        maxRetriesPerIteration: config.maxRetriesPerIteration,
        contextWindow: config.contextWindow,
        reasoning: config.reasoning,
        responseSchema: config.responseSchema,
        promptEnhancer: config.promptEnhancer,
      });

      // SSE stream
      const stream = new ReadableStream({
        async start(controller) {
          const send = (payload: { type: string; [key: string]: any }) => {
            console.log('[AgentSDK] SSE send:', payload.type, payload);
            controller.enqueue(encoder.encode(`data: ${JSON.stringify(payload)}\n\n`));
          };

          const callbacks: RuntimeCallbacks = {
            onToken: (token) => send({ type: 'token', content: token }),
            onStatus: (status) => send({ type: 'status', text: status }),
            onToolCall: (toolCall) => send({ type: 'tool_call', toolCall }),
            onConfirm: async (message, confirmId) => {
              send({ type: 'confirm', message, confirmId });
              return awaitConfirm(sessionId, confirmId);
            },
            onError: (error) => send({ type: 'error', error: error.message }),
            onIterationRetry: (reason, attempt, maxRetries) =>
              send({ type: 'iteration_retry', reason, attempt, maxRetries }),
          };

          try {
            console.log('[AgentSDK] Starting runtime.run()...');
            const result = await runtime.run(history, callbacks);
            console.log('[AgentSDK] Runtime finished:', {
              contentLength: result.content?.length,
              toolCallsCount: result.toolCalls?.length
            });

            // Salva histórico completo (incluindo tool results!)
            await historyStore.set(sessionId, result.history);

            send({ type: 'done', toolCalls: result.toolCalls });
            controller.close();
          } catch (err) {
            console.error('[AgentSDK] Stream error:', err);
            send({ type: 'error', error: String(err) });
            controller.close();
          }
        },
      });

      return new Response(stream, {
        headers: {
          'Content-Type': 'text/event-stream',
          'Cache-Control': 'no-cache',
          Connection: 'keep-alive',
        },
      });
    } catch (error) {
      console.error('[AgentSDK] Route error:', error);
      return new Response(
        JSON.stringify({ error: String(error) }),
        { status: 500, headers: { 'Content-Type': 'application/json' } }
      );
    }
  };

  // Helper para aguardar confirmação
  function awaitConfirm(
    sessionId: string,
    confirmId: string,
    timeoutMs = 60_000
  ): Promise<boolean> {
    return new Promise((resolve) => {
      const key = `${sessionId}:${confirmId}`;
      confirmPending.set(key, { resolve });
      setTimeout(() => {
        if (confirmPending.has(key)) {
          confirmPending.delete(key);
          resolve(false); // timeout = cancelado
        }
      }, timeoutMs);
    });
  }
}

async function resolveAgentRouteValue<T>(
  value: ResolvableRouteValue<T> | undefined,
  context: AgentRouteContext,
  fallback?: T
): Promise<T> {
  if (typeof value === 'function') {
    return await (value as RouteResolver<T>)(context);
  }

  if (value !== undefined) {
    return value;
  }

  if (fallback !== undefined) {
    return fallback;
  }

  throw new Error('Agent route config value is required');
}

/**
 * Provider helper para OpenAI-compatible APIs (Z.ai, Groq, Together, etc.)
 */
export function openaiProvider(config: ProviderConfig) {
  return config;
}
