/**
 * AgentRuntime - Motor de execução de agents
 *
 * Gerencia streaming, tool calling loop, retry, e histórico.
 * Baseado no código de produção do Work Log Koike.
 */

import { z } from 'zod';
import { RuntimeTool, toolsToOpenAIFormat, zodToJsonSchema, JSONSchema, type ZodSchemaLike } from './defineTool';
import {
  estimateMessagesTokens,
  truncateHistory,
  createSummaryMessage,
} from './tokens';

export interface ChatMessage {
  role: 'system' | 'user' | 'assistant' | 'tool';
  content: string | null;
  tool_calls?: ToolCall[];
  tool_call_id?: string;
}

export interface ToolCall {
  id: string;
  type: 'function';
  function: {
    name: string;
    arguments: string;
  };
}

export interface ProviderConfig {
  baseUrl: string;
  apiKey: string;
  model: string;
  /** Headers customizados */
  headers?: Record<string, string>;
}

export interface ContextWindowConfig {
  /** Maximum tokens for context window (e.g., 4000, 8000, 128000) */
  maxTokens: number;
  /** Always preserve last N messages */
  preserveLastN?: number;
  /** Summarize old messages when truncating (requires extra LLM call) */
  summarizeOld?: boolean;
}

/**
 * Structured output configuration with Zod validation
 *
 * @example
 * ```ts
 * // Com Zod (recomendado - type inference)
 * responseSchema: {
 *   zod: z.object({
 *     name: z.string(),
 *     age: z.number()
 *   })
 * }
 *
 * // Com JSON Schema (para providers que suportam)
 * responseSchema: {
 *   type: 'json_schema',
 *   schema: { type: 'object', properties: { ... } }
 * }
 *
 * // JSON genérico
 * responseSchema: {
 *   type: 'json_object'
 * }
 * ```
 */
export interface ResponseSchemaConfig<T = any> {
  /** Zod schema para validação e type inference */
  zod?: ZodSchemaLike<T>;
  /** JSON Schema para providers que suportam */
  schema?: JSONSchema;
  /** Tipo de resposta: 'json_object' (genérico) ou 'json_schema' (com schema) */
  type?: 'json_object' | 'json_schema';
}

/**
 * Prompt enhancement configuration
 */
export interface PromptEnhancerConfig {
  /** Auto-inject date/time context (default: true) */
  injectDateTimeContext?: boolean;
  /** Timezone for date formatting (default: 'America/Sao_Paulo') */
  timezone?: string;
  /** Locale for date formatting (default: 'pt-BR') */
  locale?: string;
  /** Custom base prompt that gets prepended to user prompt */
  basePrompt?: string;
  /** Custom prompt enhancer function - receives user prompt, returns enhanced prompt */
  customEnhancer?: (userPrompt: string, context: DateTimeContext) => string;
}

/**
 * Date/time context injected into prompts
 */
export interface DateTimeContext {
  /** Full date string (e.g., "sexta-feira, 28 de fevereiro de 2025") */
  fullDate: string;
  /** ISO date (e.g., "2025-02-28") */
  isoDate: string;
  /** Yesterday ISO date */
  yesterday: string;
  /** Tomorrow ISO date */
  tomorrow: string;
  /** Current month (e.g., "2025-02") */
  currentMonth: string;
  /** Current time (e.g., "14:30") */
  currentTime: string;
  /** Day of week (e.g., "sexta-feira") */
  dayOfWeek: string;
}

export interface AgentConfig<T = any> {
  provider: ProviderConfig;
  systemPrompt: string;
  tools: RuntimeTool[];
  /** Tamanho máximo do histórico (padrão: 20) - ignorado se contextWindow definido */
  historySize?: number;
  /** Temperatura (padrão: 0.5) */
  temperature?: number;
  /** Máximo de iterações de tool calling (padrão: 10) */
  maxIterations?: number;
  /** Timeout por tool execution em ms (padrão: 30000) */
  toolExecutionTimeout?: number;
  /** Máximo de retries por iteração quando tool falha com erro retryable (padrão: 2) */
  maxRetriesPerIteration?: number;
  /** Context window management (token-based truncation) */
  contextWindow?: ContextWindowConfig;
  /** Reasoning configuration */
  reasoning?: {
    enabled: boolean;
    format: 'react' | 'cot' | 'auto';
    includeInHistory?: boolean;
  };
  /** Structured output configuration with Zod validation */
  responseSchema?: ResponseSchemaConfig<T>;
  /** Prompt enhancement configuration */
  promptEnhancer?: PromptEnhancerConfig;
}

export interface RuntimeCallbacks {
  onToken?: (token: string) => void;
  onStatus?: (status: string) => void;
  onToolCall?: (toolCall: ToolCall) => void;
  onConfirm?: (message: string, confirmId: string) => Promise<boolean>;
  onError?: (error: Error) => void;
  /** Chamado quando uma iteração vai ser retryada */
  onIterationRetry?: (reason: string, attempt: number, maxRetries: number) => void;
}

/**
 * Runtime de agent com streaming e tool calling
 *
 * @example
 * ```ts
 * const runtime = new AgentRuntime({
 *   provider: {
 *     baseUrl: 'https://api.z.ai/api/paas/v4',
 *     apiKey: process.env.AI_API_KEY,
 *     model: 'glm-4.7-flash',
 *   },
 *   systemPrompt: 'Você é um assistente...',
 *   tools: [myTool],
 * });
 *
 * const result = await runtime.run(
 *   [{ role: 'user', content: 'Cria um produto' }],
 *   { onToken: (t) => console.log(t) }
 * );
 * ```
 */
export class AgentRuntime {
  private config: AgentConfig;
  private enhancedSystemPrompt: string;
  private _iterationRetryCount = 0;

  constructor(config: AgentConfig) {
    this.config = {
      ...config,
      historySize: config.historySize ?? 20,
      temperature: config.temperature ?? 0.5,
      maxIterations: config.maxIterations ?? 10,
      toolExecutionTimeout: config.toolExecutionTimeout ?? 30_000,
      maxRetriesPerIteration: config.maxRetriesPerIteration ?? 2,
    };

    // Build enhanced system prompt at construction time
    this.enhancedSystemPrompt = this.buildEnhancedSystemPrompt();
  }

  /**
   * Builds the enhanced system prompt with date/time context
   */
  private buildEnhancedSystemPrompt(): string {
    const { promptEnhancer, systemPrompt } = this.config;

    // If enhancement is disabled, return original prompt
    if (promptEnhancer?.injectDateTimeContext === false && !promptEnhancer.basePrompt && !promptEnhancer.customEnhancer) {
      return systemPrompt;
    }

    const parts: string[] = [];
    const context = this.getDateTimeContext();

    // 1. Custom enhancer takes full control
    if (promptEnhancer?.customEnhancer) {
      return promptEnhancer.customEnhancer(systemPrompt, context);
    }

    // 2. Auto-inject date/time context (default: true)
    if (promptEnhancer?.injectDateTimeContext !== false) {
      parts.push(this.formatDateTimeContext(context));
    }

    // 3. Custom base prompt (prepended)
    if (promptEnhancer?.basePrompt) {
      parts.push(promptEnhancer.basePrompt);
    }

    // 4. User's system prompt (always included)
    parts.push(systemPrompt);

    return parts.join('\n\n---\n\n');
  }

  /**
   * Gets current date/time context
   */
  private getDateTimeContext(): DateTimeContext {
    const { promptEnhancer } = this.config;
    const timezone = promptEnhancer?.timezone || 'America/Sao_Paulo';
    const locale = promptEnhancer?.locale || 'pt-BR';

    const now = new Date();

    return {
      fullDate: now.toLocaleDateString(locale, {
        dateStyle: 'full',
        timeZone: timezone,
      }),
      isoDate: this.toISODate(now, timezone),
      yesterday: this.toISODate(new Date(Date.now() - 86400000), timezone),
      tomorrow: this.toISODate(new Date(Date.now() + 86400000), timezone),
      currentMonth: this.toISODate(now, timezone).slice(0, 7),
      currentTime: now.toLocaleTimeString(locale, {
        hour: '2-digit',
        minute: '2-digit',
        timeZone: timezone,
      }),
      dayOfWeek: now.toLocaleDateString(locale, {
        weekday: 'long',
        timeZone: timezone,
      }),
    };
  }

  /**
   * Converts date to ISO format (YYYY-MM-DD) in specified timezone
   */
  private toISODate(date: Date, timezone: string): string {
    const parts = date.toLocaleDateString('pt-BR', {
      timeZone: timezone,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    }).split('/');
    return `${parts[2]}-${parts[1]}-${parts[0]}`;
  }

  /**
   * Formats date/time context for injection into prompt
   */
  private formatDateTimeContext(ctx: DateTimeContext): string {
    return `Contexto temporal:
- Data atual: ${ctx.fullDate}
- Hora atual: ${ctx.currentTime}
- Data ISO: ${ctx.isoDate}

Como interpretar datas:
- "hoje" → ${ctx.isoDate}
- "ontem" → ${ctx.yesterday}
- "amanhã" → ${ctx.tomorrow}
- "esse mês" → ${ctx.currentMonth}

Como interpretar horários:
- "9h" → 09:00
- "14h" → 14:00
- "2 da tarde" → 14:00
- "3 e meia" → 15:30
- Sempre use formato HH:MM (24h) e YYYY-MM-DD para datas`;
  }

  /**
   * Executa uma conversa com streaming e tool calling
   *
   * @returns content: texto final, toolCalls: todas as tools chamadas, history: histórico completo incluindo tool results
   */
  async run(
    messages: ChatMessage[],
    callbacks: RuntimeCallbacks = {}
  ): Promise<{ content: string; toolCalls: ToolCall[]; history: ChatMessage[]; data?: any }> {
    const allToolCalls: ToolCall[] = [];
    let iterHistory = [...messages];

    // Context window management
    if (this.config.contextWindow) {
      const { maxTokens, preserveLastN = 4, summarizeOld } = this.config.contextWindow;

      iterHistory = truncateHistory(iterHistory, maxTokens, { preserveLastN });

      // Optional: summarize old messages if still over budget
      if (summarizeOld && estimateMessagesTokens(iterHistory) > maxTokens * 0.8) {
        const oldMessages = iterHistory.slice(0, -preserveLastN);
        if (oldMessages.length > 0) {
          console.log('[AgentSDK] Summarizing', oldMessages.length, 'old messages');
          const summary = await this.summarizeOldMessages(oldMessages);
          iterHistory = [
            createSummaryMessage(summary),
            ...iterHistory.slice(-preserveLastN),
          ];
        }
      }
    } else {
      // Fallback: message count truncation (current behavior)
      if (iterHistory.length > this.config.historySize!) {
        iterHistory = iterHistory.slice(-this.config.historySize!);
      }
    }

    const systemMessage: ChatMessage = {
      role: 'system',
      content: this.enhancedSystemPrompt,
    };

    let maxIterations = this.config.maxIterations!;
    console.log('[AgentSDK] Runtime starting, maxIterations:', maxIterations);

    while (maxIterations-- > 0) {
      console.log('[AgentSDK] Iteration remaining:', maxIterations + 1);

      // Chamada streaming
      console.log('[AgentSDK] Calling LLM stream...');
      const result = await this.callLLMStream(
        [systemMessage, ...iterHistory],
        callbacks
      );

      console.log('[AgentSDK] LLM response:', {
        contentLength: result.content?.length,
        toolCallsCount: result.toolCalls?.length,
        toolNames: result.toolCalls?.map(t => t.function.name)
      });

      // Sem tool_calls = resposta final
      if (result.toolCalls.length === 0) {
        console.log('[AgentSDK] No tool calls, returning final response');
        // Adiciona resposta final ao histórico antes de retornar
        iterHistory.push({ role: 'assistant', content: result.content, tool_calls: allToolCalls.length > 0 ? allToolCalls : undefined });

        // Parse structured output if configured
        const data = this.parseStructuredOutput(result.content);

        return { content: result.content, toolCalls: allToolCalls, history: iterHistory, data };
      }

      // Registra na história
      iterHistory.push({
        role: 'assistant',
        content: result.content,
        tool_calls: result.toolCalls,
      });
      allToolCalls.push(...result.toolCalls);

      // Reasoning step (before tool execution)
      if (this.config.reasoning?.enabled && result.toolCalls.length > 0) {
        console.log('[AgentSDK] Generating reasoning before tool execution...');
        const thought = await this.generateThought(result, iterHistory);

        if (this.config.reasoning.includeInHistory) {
          // Update last assistant message to include thought
          const lastIdx = iterHistory.length - 1;
          iterHistory[lastIdx] = {
            ...iterHistory[lastIdx],
            content: `${iterHistory[lastIdx].content}\n\n[REASONING]\n${thought}\n[/REASONING]`,
          };
        }

        console.log('[AgentSDK] Reasoning:', thought.substring(0, 100) + '...');
      }

      // Valida tool calls antes de executar (detecta JSON truncado)
      const { valid: validToolCalls, invalid: invalidToolCalls } = this.validateToolCalls(result.toolCalls);

      // Adiciona erros de validação ao histórico para tools inválidas
      for (const { toolCall, error } of invalidToolCalls) {
        console.warn('[AgentSDK] Invalid tool call:', toolCall.function.name, error);
        iterHistory.push({
          role: 'tool',
          tool_call_id: toolCall.id,
          content: JSON.stringify({ success: false, error }),
        });
        allToolCalls.push(toolCall);
      }

      // Analisa dependências e executa tools válidas
      const { parallel, sequential } = this.analyzeToolDependencies(validToolCalls);

      // Executa primeiro grupo em paralelo
      let toolResults: any[] = [];
      if (parallel.length > 0) {
        console.log('[AgentSDK] Executing', parallel.length, 'tools in parallel');
        const results = await Promise.all(
          parallel.map(async (tc) => {
            callbacks.onToolCall?.(tc);
            return this.executeToolCall(tc, callbacks);
          })
        );

        // Adiciona todos os resultados ao histórico
        for (let i = 0; i < parallel.length; i++) {
          console.log('[AgentSDK] Parallel tool result:', parallel[i].function.name);
          iterHistory.push({
            role: 'tool',
            tool_call_id: parallel[i].id,
            content: JSON.stringify(results[i]),
          });
        }

        toolResults.push(...results);
      }

      // Executa tools sequenciais (que dependem das anteriores)
      for (const toolCall of sequential) {
        console.log('[AgentSDK] Executing sequential tool:', toolCall.function.name);
        callbacks.onToolCall?.(toolCall);

        const toolResult = await this.executeToolCall(toolCall, callbacks);
        console.log('[AgentSDK] Tool result:', typeof toolResult === 'string' ? toolResult?.substring(0, 100) : toolResult);

        iterHistory.push({
          role: 'tool',
          tool_call_id: toolCall.id,
          content: JSON.stringify(toolResult),
        });

        toolResults.push(toolResult);
      }

      // Retry de iteração: se alguma tool falhou com erro retryable e há retries disponíveis
      const retryableErrors = toolResults.filter(
        (r) => r?.success === false && !r?.cancelled && this.isToolErrorRetryable(r.error || '')
      );

      if (retryableErrors.length > 0) {
        const maxRetries = this.config.maxRetriesPerIteration ?? 2;
        // Conta retries desta iteração usando ref implícita (variável local)
        if (!this._iterationRetryCount) this._iterationRetryCount = 0;

        if (this._iterationRetryCount < maxRetries) {
          this._iterationRetryCount++;
          const reason = retryableErrors.map(e => e.error).join('; ');
          console.warn(`[AgentSDK] Iteration retry ${this._iterationRetryCount}/${maxRetries}: ${reason}`);
          callbacks.onIterationRetry?.(reason, this._iterationRetryCount, maxRetries);

          // Remove a última mensagem assistant + tool results do histórico (limpa estado)
          // Remove desde o último assistant até o final
          while (iterHistory.length > 0 && iterHistory[iterHistory.length - 1].role !== 'user') {
            iterHistory.pop();
          }

          // Não decrementa maxIterations - retry não conta como iteração
          maxIterations++;
          continue;
        }
      }

      // Reset retry counter only when no retryable errors occurred this iteration
      // (don't reset when retries were exhausted - tool is consistently failing)
      if (retryableErrors.length === 0) {
        this._iterationRetryCount = 0;
      }
    }

    // Limite de iterações atingido - retorna mensagem útil
    console.warn('[AgentSDK] Max iterations reached, returning partial result');
    const partialContent = iterHistory
      .filter(m => m.role === 'assistant' && m.content)
      .map(m => m.content)
      .join('\n');

    return {
      content: partialContent || 'Desculpe, não consegui completar a tarefa. Pode reformular sua solicitação?',
      toolCalls: allToolCalls,
      history: iterHistory,
      data: undefined,
    };
  }

  /**
   * Faz chamada streaming ao LLM
   */
  private async callLLMStream(
    messages: ChatMessage[],
    callbacks: RuntimeCallbacks
  ): Promise<{ content: string; toolCalls: ToolCall[] }> {
    const { provider, tools, temperature, responseSchema } = this.config;

    const url = `${provider.baseUrl}/chat/completions`;
    console.log('[AgentSDK] Calling LLM:', url);
    console.log('[AgentSDK] Model:', provider.model);
    console.log('[AgentSDK] Messages count:', messages.length);
    console.log('[AgentSDK] Tools count:', tools.length);

    // Build request body
    const body: any = {
      model: provider.model,
      messages,
      tools: toolsToOpenAIFormat(tools),
      tool_choice: 'auto',
      temperature,
      stream: true,
    };

    // Add structured output format if configured
    if (responseSchema) {
      // Determine the schema to use
      let jsonSchema: JSONSchema | undefined = responseSchema.schema;

      // Convert Zod to JSON Schema if needed
      if (responseSchema.zod && !jsonSchema) {
        jsonSchema = zodToJsonSchema(responseSchema.zod as z.ZodTypeAny);
      }

      // Determine type
      const responseType = responseSchema.type || (jsonSchema ? 'json_schema' : 'json_object');

      if (responseType === 'json_object') {
        body.response_format = { type: 'json_object' };
      } else if (responseType === 'json_schema' && jsonSchema) {
        body.response_format = {
          type: 'json_schema',
          json_schema: {
            name: 'response',
            schema: jsonSchema,
          },
        };
      }
      console.log('[AgentSDK] Using structured output:', responseType);
    }

    const response = await this.fetchWithRetry(
      url,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${provider.apiKey}`,
          Connection: 'close',
          ...provider.headers,
        },
        body: JSON.stringify(body),
      },
      3,
      () => callbacks.onStatus?.('Aguardando limite da API...')
    );

    console.log('[AgentSDK] LLM response status:', response.status);

    if (!response.ok) {
      const error = await response.text();
      console.error('[AgentSDK] LLM error:', error);
      throw new Error(`LLM API Error: ${response.status} — ${error}`);
    }

    const reader = response.body!.getReader();
    const decoder = new TextDecoder();
    let buffer = '';
    let fullContent = '';
    const toolCallAcc: Record<number, ToolCall> = {};

    outer: while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() ?? '';

      for (const line of lines) {
        if (!line.startsWith('data: ')) continue;
        const raw = line.slice(6).trim();
        if (raw === '[DONE]') break outer;

        try {
          const parsed = JSON.parse(raw);
          const delta = parsed.choices?.[0]?.delta;
          if (!delta) continue;

          // Texto em tempo real
          if (delta.content) {
            fullContent += delta.content;
            callbacks.onToken?.(delta.content);
          }

          // Acumula tool_calls
          if (delta.tool_calls) {
            for (const tc of delta.tool_calls) {
              const idx = tc.index ?? 0;
              if (!toolCallAcc[idx]) {
                toolCallAcc[idx] = {
                  id: '',
                  type: 'function',
                  function: { name: '', arguments: '' },
                };
              }
              if (tc.id) toolCallAcc[idx].id = tc.id;
              if (tc.function?.name) {
                toolCallAcc[idx].function.name += tc.function.name;
              }
              if (tc.function?.arguments) {
                toolCallAcc[idx].function.arguments += tc.function.arguments;
              }
            }
          }
        } catch (parseErr) {
          // Stream pode conter dados parciais ou corrompidos - log em debug
          if (process.env.NODE_ENV === 'development') {
            console.warn('[AgentSDK] SSE parse warning:', parseErr);
          }
        }
      }
    }

    return { content: fullContent, toolCalls: Object.values(toolCallAcc) };
  }

  /**
   * Valida tool calls antes de executar - detecta JSON truncado/inválido
   */
  private validateToolCalls(toolCalls: ToolCall[]): {
    valid: ToolCall[];
    invalid: { toolCall: ToolCall; error: string }[];
  } {
    const valid: ToolCall[] = [];
    const invalid: { toolCall: ToolCall; error: string }[] = [];

    for (const tc of toolCalls) {
      const rawArgs = tc.function.arguments;

      if (!rawArgs || rawArgs.trim() === '') {
        invalid.push({ toolCall: tc, error: 'Arguments vazios' });
        continue;
      }

      try {
        JSON.parse(rawArgs);
        valid.push(tc);
      } catch {
        invalid.push({ toolCall: tc, error: `Arguments JSON inválido (truncado): ${rawArgs.slice(0, 50)}...` });
      }
    }

    return { valid, invalid };
  }

  /**
   * Verifica se erro de tool é retryable (network/timeout)
   */
  private isToolErrorRetryable(error: string): boolean {
    const retryablePatterns = [
      'timeout', 'ETIMEDOUT', 'ECONNRESET', 'ECONNREFUSED',
      'socket', 'network', 'fetch failed',
      '500', '502', '503', '504',
    ];
    const lower = error.toLowerCase();
    return retryablePatterns.some(p => lower.includes(p.toLowerCase()));
  }

  /**
   * Executa uma tool call
   */
  private async executeToolCall(
    toolCall: ToolCall,
    callbacks: RuntimeCallbacks
  ): Promise<any> {
    const { name, arguments: rawArgs } = toolCall.function;
    let args = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;

    const tool = this.config.tools.find((t) => t.name === name);
    if (!tool) {
      return { success: false, error: `Tool não encontrada: ${name}` };
    }

    // Validação com Zod em runtime
    if (tool.zodSchema) {
      const parsed = tool.zodSchema.safeParse(args);
      if (!parsed.success) {
        const errorMessages = parsed.error.issues.map(i => i.message).join(', ');
        return {
          success: false,
          error: `Argumentos inválidos: ${errorMessages}`,
        };
      }
      // Usa dados validados
      args = parsed.data;
    }

    // Status
    const statusText = this.getToolStatusText(toolCall);
    callbacks.onStatus?.(statusText);

    try {
      // Confirmação antes de ações destrutivas
      if (tool.awaitConfirm && callbacks.onConfirm) {
        const confirmMsg = tool.confirmMessage?.(args) ?? `Executar ${name}?`;
        const confirmId = `confirm-${Date.now()}`;
        const confirmed = await callbacks.onConfirm(confirmMsg, confirmId);

        if (!confirmed) {
          return {
            success: false,
            cancelled: true,
            message: 'Usuário cancelou a ação.',
          };
        }
      }

      // Executa com timeout
      const timeout = this.config.toolExecutionTimeout ?? 30_000;
      const result = await Promise.race([
        tool.execute(args),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error(`Tool ${name} timed out after ${timeout}ms`)), timeout)
        ),
      ]);
      return { success: true, result };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error),
      };
    }
  }

  /**
   * Analisa dependências entre tools e retorna grupos paralelos vs sequenciais
   */
  private analyzeToolDependencies(toolCalls: ToolCall[]): {
    parallel: ToolCall[];
    sequential: ToolCall[];
  } {
    const parallel: ToolCall[] = [];
    const sequential: ToolCall[] = [];

    for (const tc of toolCalls) {
      const tool = this.config.tools.find((t) => t.name === tc.function.name);

      // Tool pode rodar em paralelo se:
      // 1. Não tem dependências declaradas
      // 2. parallelizable não é false
      const hasDependencies = tool?.dependencies && tool.dependencies.length > 0;
      const canParallelize = tool?.parallelizable !== false;

      if (!hasDependencies && canParallelize) {
        parallel.push(tc);
      } else {
        sequential.push(tc);
      }
    }

    return { parallel, sequential };
  }

  /**
   * Texto de status amigável por tool
   */
  private getToolStatusText(toolCall: ToolCall): string {
    const name = toolCall.function.name;
    // Mapeamento genérico - o dev pode customizar via onStatus
    const statusMap: Record<string, string> = {
      create: 'Criando...',
      update: 'Atualizando...',
      add: 'Adicionando...',
      set: 'Definindo...',
      read: 'Consultando...',
      list: 'Listando...',
      delete: 'Removendo...',
      mark: 'Marcando...',
      get: 'Buscando...',
      send: 'Enviando...',
    };

    for (const [prefix, status] of Object.entries(statusMap)) {
      if (name.startsWith(prefix)) return status;
    }

    return 'Processando...';
  }

  /**
   * Fetch com retry automático (socket errors e rate limit)
   */
  private async fetchWithRetry(
    url: string,
    init: RequestInit,
    maxRetries = 3,
    onWaiting?: () => void
  ): Promise<Response> {
    let lastError: Error = new Error('Unknown error');

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90_000);

      try {
        const res = await fetch(url, { ...init, signal: controller.signal });
        clearTimeout(timeoutId);

        // 429: rate limit
        if (res.status === 429 && attempt < maxRetries) {
          onWaiting?.();
          const retryAfter = res.headers.get('Retry-After');
          const waitMs = retryAfter
            ? parseInt(retryAfter) * 1000
            : 8_000 * attempt;
          console.warn(
            `[AgentSDK] Rate limit (429), aguardando ${waitMs}ms (tentativa ${attempt}/${maxRetries})...`
          );
          await new Promise((r) => setTimeout(r, waitMs));
          continue;
        }

        return res;
      } catch (err: any) {
        clearTimeout(timeoutId);
        lastError = err;

        const isRetryable =
          err?.cause?.code === 'UND_ERR_SOCKET' ||
          err?.cause?.code === 'ECONNRESET' ||
          err?.cause?.code === 'ECONNREFUSED' ||
          err?.name === 'AbortError';

        if (!isRetryable || attempt === maxRetries) break;

        await new Promise((r) =>
          setTimeout(r, 500 * 2 ** (attempt - 1))
        );
        console.warn(
          `[AgentSDK] Tentativa ${attempt} falhou (${err?.cause?.code ?? err?.name}), tentando novamente...`
        );
      }
    }

    throw lastError;
  }

  /**
   * Summarize old messages using LLM
   */
  private async summarizeOldMessages(messages: ChatMessage[]): Promise<string> {
    const prompt = `Summarize this conversation in 2-3 sentences, keeping key information:
${messages.map((m) => `${m.role}: ${m.content}`).join('\n')}`;

    try {
      // Make a simple non-streaming LLM call for summarization
      const { provider } = this.config;
      const url = `${provider.baseUrl}/chat/completions`;

      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${provider.apiKey}`,
          ...provider.headers,
        },
        body: JSON.stringify({
          model: provider.model,
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.3,
          max_tokens: 200,
        }),
      });

      if (!response.ok) {
        console.warn('[AgentSDK] Summary generation failed, using fallback');
        return 'Previous conversation context was summarized.';
      }

      const data = await response.json();
      return data.choices?.[0]?.message?.content || 'Previous conversation context was summarized.';
    } catch (error) {
      console.warn('[AgentSDK] Summary generation error:', error);
      return 'Previous conversation context was summarized.';
    }
  }

  /**
   * Parse and validate structured output from LLM response
   */
  private parseStructuredOutput(content: string): any {
    const { responseSchema } = this.config;
    if (!responseSchema) {
      return undefined;
    }

    try {
      const parsed = JSON.parse(content);

      // Validate with Zod if provided
      if (responseSchema.zod) {
        const result = responseSchema.zod.safeParse(parsed);
        if (!result.success) {
          const errors = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
          console.warn('[AgentSDK] Zod validation failed:', errors);
          // Return parsed data with validation errors for debugging
          return {
            _raw: parsed,
            _validationErrors: result.error.issues,
          };
        }
        console.log('[AgentSDK] Structured output validated with Zod');
        return result.data;
      }

      console.log('[AgentSDK] Parsed structured output:', typeof parsed);
      return parsed;
    } catch (error) {
      console.warn('[AgentSDK] Failed to parse structured output:', error);
      return undefined;
    }
  }

  /**
   * Generate reasoning/thought before executing tools
   */
  private async generateThought(
    result: { content: string; toolCalls: ToolCall[] },
    _history: ChatMessage[]
  ): Promise<string> {
    const format = this.config.reasoning?.format || 'react';

    const toolNames = result.toolCalls.map((tc) => tc.function.name).join(', ');

    let thoughtPrompt: string;
    if (format === 'react') {
      thoughtPrompt = `Before executing these tools: ${toolNames}

Think through:
1. What is my goal?
2. What information do I have?
3. What do I need to find out?
4. What is my execution plan?

Respond in 2-3 sentences.`;
    } else if (format === 'cot') {
      thoughtPrompt = `I'm about to use these tools: ${toolNames}

Let me think step by step about the best approach.`;
    } else {
      // 'auto' - let the LLM decide
      thoughtPrompt = `Planning to use tools: ${toolNames}

Briefly analyze the situation and plan your approach.`;
    }

    try {
      // Make a quick non-streaming LLM call for reasoning
      const { provider } = this.config;
      const url = `${provider.baseUrl}/chat/completions`;

      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${provider.apiKey}`,
          ...provider.headers,
        },
        body: JSON.stringify({
          model: provider.model,
          messages: [
            { role: 'system', content: 'You are a thoughtful AI assistant. Be concise.' },
            { role: 'user', content: thoughtPrompt },
          ],
          temperature: 0.3,
          max_tokens: 150,
        }),
      });

      if (!response.ok) {
        console.warn('[AgentSDK] Thought generation failed');
        return `Planning to use: ${toolNames}`;
      }

      const data = await response.json();
      return data.choices?.[0]?.message?.content || `Planning to use: ${toolNames}`;
    } catch (error) {
      console.warn('[AgentSDK] Thought generation error:', error);
      return `Planning to use: ${toolNames}`;
    }
  }
}
