/**
 * MCP Integration - Conecta a MCP servers e usa suas tools
 *
 * @example
 * ```ts
 * import { createMcpTools } from '@guilherme/agent-sdk/mcp';
 *
 * const fsTools = await createMcpTools({
 *   command: 'npx',
 *   args: ['-y', '@modelcontextprotocol/server-filesystem', './data'],
 * });
 * ```
 */

import { Client } from '@modelcontextprotocol/sdk/client/index.js';
import { StdioClientTransport } from '@modelcontextprotocol/sdk/client/stdio.js';
import type { RuntimeTool } from './defineTool';

export interface McpServerConfig {
  /** Comando para iniciar o MCP server (ex: 'npx', 'node') */
  command: string;
  /** Argumentos para o comando */
  args: string[];
  /** Prefixo para os nomes das tools (ex: 'fs_' → fs_read_file) */
  prefix?: string;
  /** Environment variables para o processo */
  env?: Record<string, string>;
}

export interface McpToolsResult {
  /** Tools no formato da SDK */
  tools: RuntimeTool[];
  /** Client MCP conectado */
  client: Client;
  /** Fecha a conexão com o MCP server */
  close: () => Promise<void>;
}

/**
 * Conecta a um MCP server e retorna tools no formato da SDK
 *
 * @example
 * ```ts
 * // Filesystem server
 * const { tools, close } = await createMcpTools({
 *   command: 'npx',
 *   args: ['-y', '@modelcontextprotocol/server-filesystem', './data'],
 *   prefix: 'fs_',
 * });
 *
 * // GitHub server
 * const { tools: githubTools } = await createMcpTools({
 *   command: 'npx',
 *   args: ['-y', '@modelcontextprotocol/server-github'],
 *   env: { GITHUB_TOKEN: process.env.GITHUB_TOKEN },
 * });
 *
 * // Usa as tools
 * const agent = createAgentRoute({
 *   tools: [...tools, ...githubTools],
 *   // ...
 * });
 *
 * // Quando terminar
 * await close();
 * ```
 */
export async function createMcpTools(config: McpServerConfig): Promise<McpToolsResult> {
  const { command, args, prefix = '', env } = config;

  // Cria transporte stdio (spawn do processo)
  const transport = new StdioClientTransport({
    command,
    args,
    env: env ? { ...process.env, ...env } as Record<string, string> : undefined,
  });

  // Conecta client
  const client = new Client(
    { name: 'agent-sdk-mcp', version: '1.0.0' },
    { capabilities: {} }
  );

  await client.connect(transport);

  // Descobre tools disponíveis
  const { tools: mcpTools } = await client.listTools();

  // Converte cada tool MCP para RuntimeTool
  const tools: RuntimeTool[] = mcpTools.map((mcpTool) => ({
    name: `${prefix}${mcpTool.name}`,
    description: mcpTool.description || `MCP tool: ${mcpTool.name}`,
    parameters: mcpTool.inputSchema as any,
    zodSchema: undefined, // MCP usa JSON Schema, não Zod

    execute: async (args: any) => {
      try {
        const result = await client.callTool({
          name: mcpTool.name,
          arguments: args,
        });

        // Extrai conteúdo do resultado MCP
        if (result.content && Array.isArray(result.content)) {
          const texts = result.content
            .filter((c: any) => c.type === 'text')
            .map((c: any) => c.text);

          if (texts.length > 0) {
            return texts.join('\n');
          }

          // Se não tem texto, retorna estrutura completa
          return result.content;
        }

        return result;
      } catch (error) {
        return {
          success: false,
          error: error instanceof Error ? error.message : String(error),
        };
      }
    },
  }));

  // Função para fechar conexão
  const close = async () => {
    await client.close();
  };

  return { tools, client, close };
}

/**
 * Conecta a múltiplos MCP servers de uma vez
 *
 * @example
 * ```ts
 * const { tools, closeAll } = await createMcpToolsFromServers([
 *   {
 *     command: 'npx',
 *     args: ['-y', '@modelcontextprotocol/server-filesystem', './data'],
 *     prefix: 'fs_',
 *   },
 *   {
 *     command: 'npx',
 *     args: ['-y', '@modelcontextprotocol/server-postgres'],
 *     env: { DATABASE_URL: process.env.DATABASE_URL },
 *     prefix: 'db_',
 *   },
 * ]);
 * ```
 */
export async function createMcpToolsFromServers(
  servers: McpServerConfig[]
): Promise<{ tools: RuntimeTool[]; closeAll: () => Promise<void> }> {
  const results = await Promise.all(servers.map(createMcpTools));

  const allTools = results.flatMap((r) => r.tools);
  const closeAll = async () => {
    await Promise.all(results.map((r) => r.close()));
  };

  return { tools: allTools, closeAll };
}
